  var resolvePreviewPayload = (target, tone) => {
    if (tone === "over") return PREVIEW_OVER_PAYLOAD;
    return target === "tomorrow" ? PREVIEW_TOMORROW_PAYLOAD : PREVIEW_TODAY_PAYLOAD;
  };

